180:       if (localProjects.length === 0) {
181:         localProjects = [...DEFAULT_PROJECTS];
182:         localStorage.setItem('mentor_ai_prompt_projects', JSON.stringify(localProjects));
183:       }
184: 
185:       // 2. Nếu đã đăng nhập, tải thêm từ Firestore
186:       if (user) {
187:         setSyncStatus('saving');
188:         try {
189:           const q = query(collection(db, 'projects'), where('userId', '==', user.uid));
190:           const querySnapshot = await getDocs(q);
191:           const dbProjects: PromptProject[] = [];
192:           
193:           querySnapshot.forEach((docSnap) => {
194:             const data = docSnap.data();
195:             dbProjects.push({
196:               id: docSnap.id,
197:               name: data.name,
198:               description: data.description || '',
199:               nodes: data.nodes || [],
200:               createdAt: data.createdAt?.toDate?.()?.toISOString() || data.createdAt || new Date().toISOString(),
201:               updatedAt: data.updatedAt?.toDate?.()?.toISOString() || data.updatedAt || new Date().toISOString(),
202:               userId: data.userId
203:             });
204:           });
