206:           // Trộn dự án cục bộ và đám mây (ưu tiên đám mây hoặc theo id)
207:           const merged = [...dbProjects];
208:           localProjects.forEach(lp => {
209:             if (!merged.some(mp => mp.id === lp.id)) {
210:               merged.push(lp);
211:             }
212:           });
213: 
214:           setProjects(merged);
215:           setActiveProject(merged[0] || null);
216:           setSyncStatus('synced');
217:         } catch (err) {
218:           console.error('Lỗi tải từ Firestore, fallback LocalStorage:', err);
219:           setProjects(localProjects);
220:           setActiveProject(localProjects[0] || null);
221:           setSyncStatus('local');
222:         }
223:       } else {
224:         setProjects(localProjects);
225:         setActiveProject(localProjects[0] || null);
226:         setSyncStatus('local');
227:       }
