293:         await setDoc(docRef, payload);
294:         setSyncStatus('synced');
295:       } catch (err) {
296:         console.error('Lỗi đồng bộ lên Firestore:', err);
297:         setSyncStatus('error');
298:       }
299:     } else {
300:       setSyncStatus('local');
301:     }
302:   };
