304:   // --- 2. THAO TÁC TRÊN DỰ ÁN ---
305: 
306:   const handleCreateNewProject = () => {
307:     const newId = `proj-${Date.now()}`;
308:     const newProj: PromptProject = {
309:       id: newId,
310:       name: 'Dự án Prompt mới ' + (projects.length + 1),
311:       description: 'Mô tả ngắn gọn về quy trình chuỗi prompt này.',
